mapper.select:
SELECT COUNT(*)
FROM iam_role_binding
WHERE user_id = #{userId}
  AND role_id = #{roleId}
  AND binding_scope = 'domain'
  AND business_domain_id = #{domainId}

mapper.insert:
INSERT INTO iam_role_binding (
    user_id, role_id, binding_scope, business_domain_id,
    status, created_at, updated_at
)
SELECT #{userId}, #{roleId}, 'domain', #{domainId}, 1,
       CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)
FROM DUAL
WHERE NOT EXISTS (
    SELECT 1
    FROM iam_role_binding
    WHERE user_id = #{userId}
      AND role_id = #{roleId}
      AND binding_scope = 'domain'
      AND business_domain_id = #{domainId}
)
